mapper.select:
SELECT COUNT(1)
FROM auth_sms_code
WHERE phone = #{phone}
  AND scene = #{scene}
  AND used_at IS NULL
  AND expires_at > NOW()

SELECT COUNT(1)
FROM auth_sms_code
WHERE phone = #{phone}
  AND scene = #{scene}
  AND code_hash = #{codeHash}
  AND used_at IS NULL
  AND expires_at > NOW()

mapper.update:
UPDATE auth_sms_code
SET used_at = NOW()
WHERE phone = #{phone}
  AND scene = #{scene}
  AND code_hash = #{codeHash}
  AND used_at IS NULL
  AND expires_at > NOW()
ORDER BY id DESC
LIMIT 1
